#include <iostream>
#include <fstream>
#include <string>
#include <vector>

using namespace std;

struct ConfigData {
    vector<string> keys;
    vector<string> values;
};

ConfigData* readConfigFile(const string& filename) {
    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error: Failed to open configuration file." << endl;
        return nullptr;
    }

    ConfigData* config = new ConfigData();

    string line;
    while (getline(file, line)) {
        // Skip empty lines and comments
        if (line.empty() || line[0] == '#') continue;

        // Split the line into key-value pairs
        auto pos = line.find('=');
        if (pos != string::npos) {
            config->keys.push_back(line.substr(0, pos));
            config->values.push_back(line.substr(pos + 1));
        } else {
            cerr << "Error: Invalid configuration line: " << line << endl;
        }
    }

    file.close();

    return config;
}